102:             StyleCssRule::CounterStyle(_) => unimplemented!(),
103:             StyleCssRule::Keyframes(s) => {
104:                 DomRoot::upcast(CSSKeyframesRule::new(window, parent_stylesheet, s, can_gc))
105:             },
