impl ToCss for StyleFeature {
    fn to_css<W>(&self, dest: &mut CssWriter<W>) -> fmt::Result
    where
        W: fmt::Write,
    {
        dest.write_str("--")?;
        crate::values::serialize_atom_identifier(&self.name, dest)?;
        if let Some(ref v) = self.value {
            dest.write_str(": ")?;
            v.to_css(dest)?;
