    66  impl DeepCloneWithLock for ContainerRule {
    67      fn deep_clone_with_lock(&self, lock: &SharedRwLock, guard: &SharedRwLockReadGuard) -> Self {
    68          let rules = self.rules.read_with(guard);
    69          Self {
    70              condition: self.condition.clone(),
