   316  fn eval_inline_size(context: &Context) -> Option<CSSPixelLength> {
   317      let info = context.container_info.as_ref()?;
   318      Some(CSSPixelLength::new(
   319          LogicalSize::from_physical(info.wm, info.size)
   320              .inline?
   321              .to_f32_px(),
   322      ))
   323  }
